class Solution:
    def numberOfSpecialChars(self, word: str) -> int:
        count = 0
        last_lower = {}
        for i, char in enumerate(word):
            if char.islower():
                last_lower[char] = i
            elif char.isupper() and char in last_lower and last_lower[char] < i:
                count += 1
        return count
```
